# ---------------------------------------------------------------------------
# Inlined KIMI input/weight/quant/preshuffle construction (mxfp4_moe mx path),
# verbatim from the reference benchmark harness so the test is self-contained.
# ---------------------------------------------------------------------------
from dataclasses import dataclass as _dataclass  # noqa: E402


@_dataclass(frozen=True)
class _Shape:
    NE: int
    H: int
    INTER: int
    TOPK: int


KIMI = _Shape(NE=385, H=7168, INTER=512, TOPK=9)


def _build_weights_mx(shape, device, seed=0):
    """mxfp4_moe preshuffled weights (a16w4); inlined from the KIMI harness (mx path)."""
    torch.manual_seed(seed)
    ne, h, inter = shape.NE, shape.H, shape.INTER
    torch_quant = aiter.get_torch_quant(QuantType.per_1x32)
    w1 = torch.randn((ne, 2 * inter, h), dtype=dtypes.bf16, device=device) / 10
    w2 = torch.randn((ne, h, inter), dtype=dtypes.bf16, device=device) / 10
    w1_qt, w1_scale = torch_quant(w1, quant_dtype=dtypes.fp4x2)
    w2_qt, w2_scale = torch_quant(w2, quant_dtype=dtypes.fp4x2)
    mx_w1 = shuffle_weight_a16w4(w1_qt, 16, True)
    mx_w1.shuffle_kind = "mxfp4_moe"
    return dict(
        w1=mx_w1,
        w2=shuffle_weight_a16w4(w2_qt, 16, False),
        w1_scale=shuffle_scale_a16w4(w1_scale, ne, True),
        w2_scale=shuffle_scale_a16w4(w2_scale, ne, False),
    )


def _build_inputs(shape, M, device, seed=1):
    torch.manual_seed(seed)
    ne, h, topk = shape.NE, shape.H, shape.TOPK
    hidden = torch.randn((M, h), dtype=dtypes.bf16, device=device) / 10
    n_routed = ne - 1
    shared_id = ne - 1
    n_topk_routed = topk - 1
    g = torch.Generator(device=device).manual_seed(seed)
    bias = torch.randn(n_routed, generator=g, device=device) * 0.5
    scores = torch.randn(M, n_routed, generator=g, device=device) + bias
    routed_w, routed_ids = torch.topk(scores.softmax(-1), n_topk_routed, dim=-1)
    shared_ids = torch.full((M, 1), shared_id, device=device, dtype=routed_ids.dtype)
    shared_w = torch.ones((M, 1), device=device, dtype=routed_w.dtype)
    topk_ids = torch.cat([shared_ids, routed_ids], dim=1).to(torch.int32)
    topk_weight = torch.cat([shared_w, routed_w], dim=1).to(torch.float32)
    return hidden, topk_ids, topk_weight


SHAPE = KIMI  # NE=385, H=7168, INTER=512, TOPK=9

# ---------------------------------------------------------------------------
# Compile-time constants common to all gemm1 stage-1 variants (KIMI shape).
# ---------------------------------------------------------------------------
NE = SHAPE.NE  # 385
K = SHAPE.H  # 7168  (D_HIDDEN)
D_INTER = SHAPE.INTER  # 512
TOPK = SHAPE.TOPK  # 9
N_OUT = 2 * D_INTER  # 1024  (gate||up width)
MAX_M = 655360

N_INTER = N_OUT // 2  # 512   (swiglu output width, fp4 elems)
K_G2_HALF = N_INTER // 2  # 256   (packed-fp4 output row stride, bytes)
INTER_SCALE_COLS = D_INTER // 32  # 16    (e8m0 cols of inter scale)


# ---------------------------------------------------------------------------
# CSV-driven variant selection (kimik2_5_mxfp4_tuned_fmoe.csv, column block_m /
# kernelName1).  Each entry is the gemm1 stage-1 variant the tuned config picks
# for the token bucket containing M.
# ---------------------------------------------------------------------------
class Variant:
    __slots__ = ("name", "bm", "use_nt", "inline_quant", "kernel_tag")

    def __init__(self, name, bm, use_nt, inline_quant, kernel_tag):
        self.name = name
        self.bm = bm
        self.use_nt = use_nt
        self.inline_quant = inline_quant
        self.kernel_tag = kernel_tag

    @property
    def kernel_name(self):
        return f"mxfp4_moe_g1_a4w4_NE{NE}_H{K}_E{D_INTER}_{self.kernel_tag}"


_VARIANTS = {
    "BM16_INLINEQUANT": Variant(
        "BM16_INLINEQUANT",
        bm=16,
        use_nt=True,
        inline_quant=True,
        kernel_tag="BM16_INLINEQUANT",
    ),
    "BM32_NT": Variant(
        "BM32_NT",
        bm=32,
        use_nt=True,
        inline_quant=False,
        kernel_tag="BM32_NT",
    ),
    "BM32_CACHED": Variant(
        "BM32_CACHED",
        bm=32,
        use_nt=False,
        inline_quant=False,
        kernel_tag="BM32_CACHED",
    ),
    "BM128": Variant(
        "BM128",
        bm=128,
        use_nt=False,
        inline_quant=False,
        kernel_tag="BM128",
    ),
}


def _variant_for_M(M):
    """Mirror the CSV token-bucket dispatch (gemm1 stage-1 variant for token M)."""
    if M <= 128:
        return _VARIANTS["BM16_INLINEQUANT"]
    if M <= 512:
        return _VARIANTS["BM32_NT"]
    if M <= 2048:
        return _VARIANTS["BM32_CACHED"]
    return _VARIANTS["BM128"]


# ---------------------------------------------------------------------------
# Run the production gemm1 prologue (sort -> quant -> sort_scales), returning
# every tensor that the gemm1 kernel (HIP golden and FlyDSL port) consumes.
# This mirrors the threestage branch of aiter.fused_moe._mxfp4_moe_run.
# ---------------------------------------------------------------------------
def _prepare_gemm1_inputs(M, variant, seed):
    device = torch.device("cuda")
    BM = variant.bm

    # KIMI weights (mxfp4_moe preshuffle) + KIMI inputs from the harness.
    mx = _build_weights_mx(SHAPE, device, seed=seed)
    hidden, topk_ids, topk_weight = _build_inputs(SHAPE, M, device, seed=seed + 1)

    w1 = mx["w1"]
    w1_scale = mx["w1_scale"]
    if w1.element_size() == 1 and w1.dtype != torch.uint8:
        w1 = w1.view(torch.uint8)

    D_HIDDEN = hidden.shape[1]
    assert D_HIDDEN == K
    assert w1.shape[0] == NE
    assert w1.shape[1] == N_OUT

    # max_sorted: tight upper bound on cumsum (sum over experts of round_up(count_e, BM)).
    active = min(NE, M * TOPK)
    cumsum_max = M * TOPK + active * (BM - 1)
    max_sorted = ((cumsum_max + BM - 1) // BM) * BM

    sorted_token_ids = torch.empty((max_sorted,), device=device, dtype=dtypes.i32)
    sorted_expert_ids = torch.empty((max_sorted // BM,), device=device, dtype=dtypes.i32)
    cumsum_tensor = torch.empty((1,), device=device, dtype=dtypes.i32)
    reverse_sorted = torch.empty((M * TOPK,), device=device, dtype=dtypes.i32)
    sorted_weights = torch.empty((max_sorted,), device=device, dtype=dtypes.fp32)
    masked_m = torch.empty((NE,), device=device, dtype=dtypes.i32)
    m_indices = torch.empty((max_sorted,), device=device, dtype=dtypes.i32)

    # Quant buffers. The inline_quant path leaves these as placeholders (gemm1's
    # kInlineQuant generates a_q / a_scale itself) but they are still allocated
    # (real buffer descriptors), mirroring _mxfp4_moe_run.
    a_quant = torch.empty((M, D_HIDDEN // 2), device=device, dtype=torch.uint8)
    a_scale = torch.empty((M, D_HIDDEN // 32), device=device, dtype=torch.uint8)

    def _empty_bf16():
        return torch.empty((0,), dtype=dtypes.bf16, device=device)

    def _empty_u8():
        return torch.empty((0,), dtype=torch.uint8, device=device)

    # Sort + (optional) quant + (optional) sort_scales.  This mirrors the two
    # prologue branches of aiter.fused_moe._mxfp4_moe_run exactly:
    #   threestage  : sort(prologue=1) -> quant -> sort_scales
    #   inline_quant: sort(prologue=0) only; gemm1 quantises bf16 hidden inline,
    #                 so a_scale_sorted_shuffled is a tiny unused placeholder.
    if not variant.inline_quant:
        aiter.mxfp4_moe_sort(
            topk_ids=topk_ids,
            topk_weight=topk_weight,
            sorted_token_ids=sorted_token_ids,
            sorted_expert_ids=sorted_expert_ids,
            cumsum_tensor=cumsum_tensor,
            reverse_sorted=reverse_sorted,
            sorted_weights=sorted_weights,
            masked_m=masked_m,
            m_indices=m_indices,
            bf16_zero_out=_empty_bf16(),
            bf16_zero_workspace=_empty_bf16(),
            M_logical=M,
            NE=NE,
            TOPK=TOPK,
            D_HIDDEN=D_HIDDEN,
            D_INTER=D_INTER,
            MB=BM,
            prologue=1,
        )
        aiter.mxfp4_moe_quant(
            a_input=hidden,
            a_quant=a_quant,
            a_scale=a_scale,
            bf16_zero_out=_empty_bf16(),
            NE=NE,
            TOPK=TOPK,
            D_HIDDEN=D_HIDDEN,
            MB=BM,
        )
        padded_rows = ((max_sorted + 31) // 32) * 32
        cols = D_HIDDEN // 32
        a_scale_sorted_shuffled = torch.empty((padded_rows * cols * 2,), device=device, dtype=torch.uint8)
        aiter.mxfp4_moe_sort_scales(
            a_scale=a_scale,
            sorted_token_ids=sorted_token_ids,
            cumsum_tensor=cumsum_tensor,
            a_scale_sorted_shuffled=a_scale_sorted_shuffled,
            NE=NE,
            TOPK=TOPK,
            D_HIDDEN=D_HIDDEN,
            D_INTER=D_INTER,
            MB=BM,
            max_sorted=max_sorted,
        )
    else:
        aiter.mxfp4_moe_sort(
            topk_ids=topk_ids,
            topk_weight=topk_weight,
            sorted_token_ids=sorted_token_ids,
            sorted_expert_ids=sorted_expert_ids,
            cumsum_tensor=cumsum_tensor,
            reverse_sorted=reverse_sorted,
            sorted_weights=sorted_weights,
            masked_m=masked_m,
            m_indices=m_indices,
            bf16_zero_out=_empty_bf16(),
            bf16_zero_workspace=_empty_bf16(),
            M_logical=M,
            NE=NE,
            TOPK=TOPK,
            D_HIDDEN=D_HIDDEN,
            D_INTER=D_INTER,
            MB=BM,
            prologue=0,
        )
        # gemm1 (kInlineQuant) will not read this; tiny placeholder.
        a_scale_sorted_shuffled = _empty_u8()
    torch.cuda.synchronize()

    # gemm1 output buffer sizes (mirror _mxfp4_moe_run exactly; BM-independent
    # BM_MIN=64 packing for the inter scale).
    BM_MIN = 64
    inter_scale_cols = D_INTER // 32
    inter_scale_bytes = max_sorted * (1024 // BM_MIN) * 4
    inter_scale_rows = (inter_scale_bytes + inter_scale_cols - 1) // inter_scale_cols
    inter_scale_rows = (inter_scale_rows + 31) // 32 * 32

    return {
        "device": device,
        "M": M,
        "bm": BM,
        "hidden": hidden,
        "w1": w1,
        "w1_scale": w1_scale,
        "a_quant": a_quant,
        "a_scale_sorted_shuffled": a_scale_sorted_shuffled,
        "cumsum_tensor": cumsum_tensor,
        "sorted_expert_ids": sorted_expert_ids,
        "m_indices": m_indices,
        "max_sorted": max_sorted,
        "inter_q_shape": (max_sorted, D_INTER // 2),
        "inter_scale_shape": (inter_scale_rows, inter_scale_cols),
        "total_m_blocks": int(cumsum_tensor.item()) // BM,
    }


def _alloc_outputs(inp):
    device = inp["device"]
    inter_q = torch.zeros(inp["inter_q_shape"], device=device, dtype=torch.uint8)
    inter_scale = torch.zeros(inp["inter_scale_shape"], device=device, dtype=torch.uint8)
    return inter_q, inter_scale


# ---------------------------------------------------------------------------
# Golden: the HIP / aiter gemm1 kernel (variant selected by kernelName).
# ---------------------------------------------------------------------------
def _run_hip_gemm1(inp, variant, inter_q, inter_scale):
    aiter.mxfp4_moe_gemm1_a4w4(
        cumsum_tensor=inp["cumsum_tensor"],
        a_quant=inp["a_quant"],
        a_scale_sorted_shuffled=inp["a_scale_sorted_shuffled"],
        w12_shuffled_quant=inp["w1"],
        w12_shuffled_scale=inp["w1_scale"],
        sorted_expert_ids=inp["sorted_expert_ids"],
        m_indices=inp["m_indices"],
        inter_sorted_quant=inter_q,
        inter_sorted_shuffled_scale=inter_scale,
        hidden_states=inp["hidden"],
        kernelName=variant.kernel_name,
    )
    torch.cuda.synchronize()


# ---------------------------------------------------------------------------
# FlyDSL port on the SAME tensors (parameterised per CSV variant).
# ---------------------------------------------------------------------------
def _run_flydsl_gemm1(inp, variant, inter_q, inter_scale):
    if _REPO_ROOT not in sys.path:
        sys.path.insert(0, _REPO_ROOT)
    from kernels.gemm1_a4w4 import compile_gemm1_a4w4

    BM = variant.bm
    launch = compile_gemm1_a4w4(
        MAX_M=MAX_M,
        NUM_EXPERTS=NE,
        K=K,
        N_OUT=N_OUT,
        BM=BM,
        kUseNT=variant.use_nt,
        kInlineQuant=variant.inline_quant,
        kXcdSwizzle=0,
    )

    # Grid identical to the HIP launch():  the over-provisioned max_m_blocks form
    # (kernel early-returns for pid >= total_tiles).
    num_n_blocks = N_OUT // 256
    n_tokens = int(inp["M"])
    if BM == 128:
        max_m_blocks = (n_tokens * TOPK + NE * (BM - 1) + BM - 1) // BM
    else:
        active = min(n_tokens * TOPK, NE)
        max_m_blocks = (n_tokens * TOPK + active * (BM - 1) + BM - 1) // BM
    grid = max_m_blocks * num_n_blocks

    stream = torch.cuda.Stream()

    # The FlyDSL port consumes every operand as raw bytes (buffer resources), so
    # normalise the fp4/e8m0 tensors to uint8 -- the FlyDSL tensor adaptor does
    # not understand torch's float4/float8_e8m0 DLPack dtype codes.  The HIP
    # golden took the same buffers (it reads raw bytes either way), so the bytes
    # fed to both kernels are identical.
    def _u8(t):
        return t.view(torch.uint8) if t.element_size() == 1 and t.dtype != torch.uint8 else t

    w1_bytes = _u8(inp["w1"])
    w1_scale_bytes = _u8(inp["w1_scale"])
    a_quant_bytes = _u8(inp["a_quant"])

    # For the inline-quant variant a_scale_sorted_shuffled is the empty
    # placeholder (gemm1 quantises inline and never reads it).  FlyDSL's tensor
    # marshalling needs a valid (non-empty) buffer base, so substitute a tiny
    # 1-byte placeholder the kernel won't read.  The HIP golden took the same
    # ignored buffer.
    a_scale_src = inp["a_scale_sorted_shuffled"]
    if a_scale_src.numel() == 0:
        a_scale_src = torch.zeros((1,), device=inp["device"], dtype=torch.uint8)
    a_scale_bytes = _u8(a_scale_src)

    launch(
        a_quant_bytes,
        a_scale_bytes,
        w1_bytes,
        w1_scale_bytes,
        inp["sorted_expert_ids"],
        inp["cumsum_tensor"],
        inp["m_indices"],
        n_tokens,
        inter_q,
        inter_scale,
        inp["hidden"],
        int(grid),
        stream=stream,
    )
    torch.cuda.synchronize()


# ---------------------------------------------------------------------------
# fp4 (e2m1) dequant helper for the output comparison.
# ---------------------------------------------------------------------------
_FP4_E2M1_LUT = np.array(
    [0.0, 0.5, 1.0, 1.5, 2.0, 3.0, 4.0, 6.0, -0.0, -0.5, -1.0, -1.5, -2.0, -3.0, -4.0, -6.0],
    dtype=np.float32,
)


def _dequant_packed_fp4(packed_bytes_np):
    """Dequant packed fp4 (scale=1) onto the e2m1 grid; 2 fp4 per byte."""
    lo = _FP4_E2M1_LUT[(packed_bytes_np & 0x0F).astype(np.int64)]
    hi = _FP4_E2M1_LUT[(packed_bytes_np >> 4).astype(np.int64)]
    vals = np.empty(packed_bytes_np.shape[:-1] + (packed_bytes_np.shape[-1] * 2,), np.float32)
    vals[..., 0::2] = lo
    vals[..., 1::2] = hi
    return vals


# ---------------------------------------------------------------------------
# The test: gemm1 in isolation, FlyDSL vs HIP/aiter golden, for every CSV
# variant (selected by token M).  8 iterations -> 8 (M) parameters covering all
# four stage-1 gemm1 kernels:
#   M=16,64   -> BM16_INLINEQUANT
#   M=256,512 -> BM32_NT
#   M=1024    -> BM32_CACHED   (already supported; kept working)
#   M=2048    -> BM32_CACHED
#   M=4096    -> BM128
#   M=8192    -> BM128
# ---------------------------------------------------------------------------
@pytest.mark.parametrize("M", [16, 64, 256, 512, 1024, 2048, 4096, 8192])
def test_gemm1_a4w4_matches_hip(M):
    variant = _variant_for_M(M)

    inp = _prepare_gemm1_inputs(M, variant, seed=0)
    assert inp["total_m_blocks"] > 0, "prologue produced no work (cumsum==0)"

    # ---- HIP / aiter golden ----
    ref_q, ref_scale = _alloc_outputs(inp)
    _run_hip_gemm1(inp, variant, ref_q, ref_scale)

    # ---- FlyDSL port (same inputs, fresh output buffers) ----
    fly_q, fly_scale = _alloc_outputs(inp)
    _run_flydsl_gemm1(inp, variant, fly_q, fly_scale)

    ref_q_np = ref_q.cpu().numpy()
    fly_q_np = fly_q.cpu().numpy()
    ref_scale_np = ref_scale.cpu().numpy()
    fly_scale_np = fly_scale.cpu().numpy()

    # Sanity: the golden must have actually written output (not all-zero).
    assert ref_q_np.any(), f"HIP/aiter gemm1 golden ({variant.kernel_name}) produced all-zero " f"output - bad setup"

    # Only the populated rows are meaningful: the kernel writes total_m_blocks*BM
    # logical rows of packed-fp4 output (out_row = m_row + row_local).
    rows = inp["total_m_blocks"] * variant.bm

    # ---- 1) e8m0 scale bytes must match the golden ----
    # e8m0 are integer exponents of the per-block scale.  They must agree with
    # the HIP golden, EXCEPT for tie-break jitter: a handful of accumulated
    # values land exactly on an e2m1 rounding boundary, where the golden itself
    # is run-to-run non-deterministic (MFMA reduction / cross-wave DPP amax
    # order) and flips the exponent by +/-1.  We therefore require:
    #   * exponents differing by more than 1 -> hard fail (real scale error),
    #   * at most a negligible fraction (<=0.01%) may differ by exactly 1.
    # This rejects any systematic scale divergence while tolerating only the
    # boundary jitter the reference kernel exhibits against itself.
    sc_ref_flat = ref_scale_np.reshape(-1).astype(np.int32)
    sc_fly_flat = fly_scale_np.reshape(-1).astype(np.int32)
    sc_diff = np.abs(sc_fly_flat - sc_ref_flat)
    n_big = int((sc_diff > 1).sum())
    n_one = int((sc_diff == 1).sum())
    frac_one = n_one / sc_diff.size
    assert n_big == 0 and frac_one <= 1e-4, (
        f"inter_sorted_shuffled_scale (e8m0) mismatch FlyDSL vs HIP golden for "
        f"{variant.name} (M={M}): {n_big} elements differ by >1 exponent, "
        f"{n_one} ({frac_one:.4%}) differ by exactly 1 "
        f"(allowed: 0 big, <=0.01% one-off boundary jitter)."
    )

    # ---- 2) dequantised packed-fp4 output: rtol=1e-3 ----
    packed_ref = ref_q_np[:rows].reshape(rows, K_G2_HALF)
    packed_fly = fly_q_np[:rows].reshape(rows, K_G2_HALF)

    nibble_eq = (packed_ref == packed_fly).mean()

    deq_ref = _dequant_packed_fp4(packed_ref).reshape(-1)
    deq_fly = _dequant_packed_fp4(packed_fly).reshape(-1)

    # Both kernels quantise to the SAME e2m1 grid; the minimum nonzero gap on the
    # grid is 0.5, so rtol=1e-3 / atol=1e-3 is satisfied iff the fp4 codes agree.
    # This keeps the rtol=0.001 target meaningful while respecting the
    # exact-integer nature of the packed fp4 output.  A negligible fraction
    # (<=0.01%) of accumulated values land exactly on an e2m1 rounding boundary
    # where the reference kernel itself is run-to-run non-deterministic (the
    # MFMA reduction / cross-wave DPP amax order) and emits a neighbouring fp4
    # code; we allow only that boundary jitter, NOT systematic mismatch.
    tol = 1e-3 * np.abs(deq_ref) + 1e-3
    violations = np.abs(deq_fly - deq_ref) > tol
    n_viol = int(violations.sum())
    frac_viol = n_viol / deq_ref.size
    assert frac_viol <= 1e-4, (
        f"gemm1 packed-fp4 output mismatch for {variant.name} (M={M}): "
        f"{n_viol} ({frac_viol:.4%}) elements exceed rtol=1e-3/atol=1e-3 "
        f"(allowed: <=0.01% e2m1 boundary jitter; nibble exact match = "
        f"{nibble_eq:.4%}).  Max abs diff among violations = "
        f"{float(np.abs(deq_fly - deq_ref)[violations].max()) if n_viol else 0.0}."
    )


if __name__ == "__main__":
    sys.exit(pytest.main([__file__, "-v", "-s"]))
